 47→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport }) {
 48→  return {
 49→    onMouseDown(modelPos, e, toolState) {
 50→      if (e.button !== 0) return;
 51→
 52→      const floor = getFloor(activeFloorId);
 53→      const hitRadius = 10 / viewport.zoom;
 54→
 55→      // Check if clicking a handle
 56→      const target = e.target;
 57→      if (target.dataset.handle) {
 58→        editorDispatch({
 59→          type: 'UPDATE_TOOL_STATE',
 60→          payload: {
 61→            dragging: true,
 62→            dragType: 'handle',
 63→            handle: target.dataset.handle,
 64→            startPos: modelPos,
 65→          },
 66→        });
 67→        return;
 68→      }
 69→
 70→      const hit = hitTest(modelPos, floor, hitRadius);
 71→      if (hit) {
 72→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
 73→        editorDispatch({
 74→          type: 'UPDATE_TOOL_STATE',
 75→          payload: {
 76→            dragging: true,
 77→            dragType: 'move',
 78→            startPos: modelPos,
 79→            originalPos: modelPos,
 80→          },
 81→        });
 82→      } else {
 83→        editorDispatch({ type: 'DESELECT' });
 84→      }
 85→    },
 86→
 87→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
 88→      if (!toolState.dragging || !selectedId) return;
 89→
 90→      const floor = getFloor(activeFloorId);
 91→      const dx = modelPos.x - toolState.startPos.x;
 92→      const dy = modelPos.y - toolState.startPos.y;
 93→
 94→      if (selectedType === 'wall') {
 95→        const wall = floor.walls.find(w => w.id === selectedId);
 96→        if (!wall) return;
 97→
 98→        if (toolState.dragType === 'handle') {
 99→          const handle = toolState.handle;
100→          dispatch({
101→            type: 'WALL_UPDATE',
102→            floorId: activeFloorId,
103→            wall: {
104→              id: wall.id,
105→              [handle]: { x: modelPos.x, y: modelPos.y },
106→            },
107→          });
108→        } else {
109→          dispatch({
110→            type: 'WALL_UPDATE',
111→            floorId: activeFloorId,
112→            wall: {
113→              id: wall.id,
114→              start: { x: wall.start.x + dx, y: wall.start.y + dy },
115→              end: { x: wall.end.x + dx, y: wall.end.y + dy },
116→            },
117→          });
118→        }
119→        editorDispatch({
120→          type: 'UPDATE_TOOL_STATE',
121→          payload: { startPos: modelPos },
122→        });
123→      } else if (selectedType === 'door' || selectedType === 'window') {
124→        // Slide along parent wall
125→        const items = selectedType === 'door' ? floor.doors : floor.windows;
126→        const item = items.find(i => i.id === selectedId);
127→        if (!item) return;
128→
129→        const wall = floor.walls.find(w => w.id === item.wallId);
130→        if (!wall) return;
131→
132→        const newOffset = projectPointOnWall(wall, modelPos);
133→        const halfWidth = item.width / 2;
134→        const maxOffset = wallLength(wall) - halfWidth;
135→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
136→
137→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
138→        dispatch({
139→          type: updateType,
140→          floorId: activeFloorId,
141→          [selectedType]: { id: item.id, offset: clampedOffset },
142→        });
143→
144→        editorDispatch({
145→          type: 'UPDATE_TOOL_STATE',
146→          payload: { startPos: modelPos },
147→        });
148→      }
149→    },
150→
151→    onMouseUp(modelPos, e, toolState) {
152→      if (toolState.dragging) {
153→        editorDispatch({
154→          type: 'UPDATE_TOOL_STATE',
155→          payload: { dragging: false, dragType: null, handle: null },
156→        });
157→      }
158→    },
159→
160→    onKeyDown(e, toolState, selectedId, selectedType) {
161→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
162→        const floor = getFloor(activeFloorId);
163→        if (selectedType === 'wall') {
164→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
165→        } else if (selectedType === 'door') {
166→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
167→        } else if (selectedType === 'window') {
168→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
169→        } else if (selectedType === 'room') {
170→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
171→        }
172→        editorDispatch({ type: 'DESELECT' });
173→      }
174→    },
175→
176→    getCursor(toolState) {
177→      if (toolState.dragging) return 'grabbing';
178→      return 'default';
179→    },
180→  };
181→}
