  1→import { createWall } from '@/domain/models';
  2→import { distance } from '@/geometry/point';
  3→import { nearestPointOnSegment } from '@/geometry/line';
  4→import { SNAP_DISTANCE_PX, MIN_WALL_LENGTH } from '@/domain/defaults';
  5→
  6→function snapToWalls(modelPos, walls, snapDistModel, chainStart) {
  7→  let best = null;
  8→  let bestDist = snapDistModel;
  9→
 10→  // Snap to chain start to close loop (highest priority)
 11→  if (chainStart) {
 12→    const d = distance(modelPos, chainStart);
 13→    if (d < bestDist) {
 14→      best = chainStart;
 15→      bestDist = d;
 16→    }
 17→  }
 18→
 19→  // Snap to wall endpoints
 20→  for (const wall of walls) {
 21→    for (const pt of [wall.start, wall.end]) {
 22→      const d = distance(modelPos, pt);
 23→      if (d < bestDist) {
 24→        best = pt;
 25→        bestDist = d;
 26→      }
 27→    }
 28→  }
 29→
 30→  // If no endpoint found, try snapping to nearest point on wall segments
 31→  if (!best) {
 32→    for (const wall of walls) {
 33→      const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
 34→      if (t <= 0.001 || t >= 0.999) continue; // too close to endpoints, already covered
 35→      const d = distance(modelPos, point);
 36→      if (d < bestDist) {
 37→        best = point;
 38→        bestDist = d;
 39→      }
 40→    }
 41→  }
 42→
 43→  return best;
 44→}
 45→
 46→function constrainAngle(start, end, shiftHeld) {
 47→  if (!shiftHeld) return end;
 48→  const dx = end.x - start.x;
 49→  const dy = end.y - start.y;
 50→  const angle = Math.atan2(dy, dx);
 51→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 52→  const len = Math.sqrt(dx * dx + dy * dy);
 53→  return {
 54→    x: start.x + Math.cos(snapAngle) * len,
 55→    y: start.y + Math.sin(snapAngle) * len,
 56→  };
 57→}
 58→
 59→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 60→  return {
 61→    onMouseDown(modelPos, e, toolState) {
 62→      if (e.button !== 0) return;
 63→
 64→      const floor = getFloor(activeFloorId);
 65→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 66→      const shiftHeld = e.shiftKey;
 67→
 68→      let snapped = modelPos;
 69→      if (snapEnabled) {
 70→        const snapPt = snapToWalls(modelPos, floor.walls, snapDistModel, toolState.chainStart);
 71→        if (snapPt) snapped = { ...snapPt };
 72→      }
 73→      if (shiftHeld && toolState.start) {
 74→        snapped = constrainAngle(toolState.start, snapped, true);
 75→      }
 76→
 77→      if (!toolState.start) {
 78→        // First click: set start
 79→        editorDispatch({
 80→          type: 'UPDATE_TOOL_STATE',
 81→          payload: { start: snapped, chainStart: snapped, preview: null },
 82→        });
 83→      } else {
 84→        // Second+ click: create wall and chain
 85→        const endPt = snapped;
 86→
 87→        const len = distance(toolState.start, endPt);
 88→        if (len < MIN_WALL_LENGTH) return;
 89→
 90→        const wall = createWall(toolState.start, endPt);
 91→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
 92→
 93→        // Check if we snapped back to chain start (close loop)
 94→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
 95→          editorDispatch({
 96→            type: 'UPDATE_TOOL_STATE',
 97→            payload: { start: null, chainStart: null, preview: null },
 98→          });
 99→        } else {
100→          // Chain: end becomes new start
101→          editorDispatch({
102→            type: 'UPDATE_TOOL_STATE',
103→            payload: { start: endPt, preview: null },
104→          });
105→        }
106→      }
107→    },
108→
109→    onMouseMove(modelPos, e, toolState) {
110→      if (!toolState.start) return;
111→      let preview = modelPos;
112→
113→      const floor = getFloor(activeFloorId);
114→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
115→      if (snapEnabled) {
116→        const snapPt = snapToWalls(modelPos, floor.walls, snapDistModel, toolState.chainStart);
117→        if (snapPt) preview = { ...snapPt };
118→      }
119→      if (e.shiftKey) {
120→        preview = constrainAngle(toolState.start, preview, true);
121→      }
122→
123→      editorDispatch({
124→        type: 'UPDATE_TOOL_STATE',
125→        payload: { preview },
126→      });
127→    },
128→
129→    onDoubleClick(modelPos, e, toolState) {
130→      // Finish chain
131→      editorDispatch({
132→        type: 'UPDATE_TOOL_STATE',
133→        payload: { start: null, chainStart: null, preview: null },
134→      });
135→    },
136→
137→    onKeyDown(e, toolState) {
138→      if (e.key === 'Escape') {
139→        editorDispatch({
140→          type: 'UPDATE_TOOL_STATE',
141→          payload: { start: null, chainStart: null, preview: null },
142→        });
143→      }
144→    },
145→
146→    getCursor(toolState) {
147→      return 'crosshair';
148→    },
149→  };
150→}
