 70→function SlidingDoor({ door, info }) {
 71→  const flipSign = door.openDirection === 'right' ? -1 : 1;
 72→  const angleDeg = (info.angle * 180) / Math.PI;
 73→  const arrowY = flipSign * -12;
 74→  const arrowStart = 0.2 * door.width;
 75→  const arrowEnd = 0.8 * door.width;
 76→
 77→  return (
 78→    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
 79→      {/* Thick panel line */}
 80→      <line
 81→        x1={0} y1={0}
