### Step 2: Column Geometry (Pure Functions)

**New file: `C:\Users\johnm\modular apartment planner\src\geometry\columnGeometry.js`**

This file follows the same pattern as `wallGeometry.js` -- pure geometry functions that take plain column objects and return point arrays, with no React dependency.

```js
import { rotate } from './point';

/**
 * Returns the 4 corner points of a column's outline, accounting for rotation.
 * Column is defined by center (x,y), width (x-dim), depth (y-dim), rotation (degrees).
 * Returns array of 4 points in CW order: [topLeft, topRight, bottomRight, bottomLeft]
 */
export function columnOutline(column) {
  const hw = column.width / 2;
  const hd = column.depth / 2;
  const cx = column.x;
  const cy = column.y;
  const rot = column.rotation || 0;

  // Unrotated corners relative to center
  const corners = [
    { x: cx - hw, y: cy - hd },  // top-left
    { x: cx + hw, y: cy - hd },  // top-right
    { x: cx + hw, y: cy + hd },  // bottom-right
    { x: cx - hw, y: cy + hd },  // bottom-left
  ];

  if (rot === 0) return corners;
  const center = { x: cx, y: cy };
  return corners.map(p => rotate(p, center, rot));
}

/**
 * Returns the center point of a column.
 */
export function columnCenter(column) {
  return { x: column.x, y: column.y };
}

/**
 * Returns all snap-worthy points for a column: center + 4 corners.
 * Used by wallDrawHandler for snapping wall endpoints to columns.
 */
export function columnSnapPoints(column) {
  const corners = columnOutline(column);
  return [
    { x: column.x, y: column.y },  // center first (highest priority)
    ...corners,
  ];
}

/**
 * Returns the 4 edge midpoints of a column (for finer snapping if desired).
 */
export function columnEdgeMidpoints(column) {
  const corners = columnOutline(column);
  return corners.map((c, i) => {
    const next = corners[(i + 1) % 4];
    return { x: (c.x + next.x) / 2, y: (c.y + next.y) / 2 };
  });
}
```

The `rotate` function already exists in `src/geometry/point.js` (line 15) and takes `(point, center, angleDeg)`, returning a rotated point. This is exactly what is needed.

