import { createColumn } from '@/domain/models';
import { SNAP_DISTANCE_PX, GRID_MINOR } from '@/domain/defaults';

function snapToGrid(modelPos, snapDistModel) {
  const gridSize = GRID_MINOR; // 100mm grid
  const snappedX = Math.round(modelPos.x / gridSize) * gridSize;
  const snappedY = Math.round(modelPos.y / gridSize) * gridSize;
  // Only snap if close enough
  if (Math.abs(modelPos.x - snappedX) < snapDistModel &&
      Math.abs(modelPos.y - snappedY) < snapDistModel) {
    return { x: snappedX, y: snappedY };
  }
  return modelPos;
}

export function createColumnPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
  return {
    onMouseMove(modelPos, e, toolState) {
      let pos = { ...modelPos };
      if (snapEnabled) {
        const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
        pos = snapToGrid(pos, snapDistModel);
      }
      editorDispatch({
        type: 'UPDATE_TOOL_STATE',
        payload: { previewX: pos.x, previewY: pos.y },
      });
    },

    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;
      const x = toolState.previewX ?? modelPos.x;
      const y = toolState.previewY ?? modelPos.y;
      const column = createColumn(x, y);
      dispatch({ type: 'COLUMN_ADD', floorId: activeFloorId, column });
    },

    onKeyDown(e, toolState) {
      if (e.key === 'Escape') {
        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
      }
    },

    getCursor(toolState) {
      return 'crosshair';
    },
  };
}
