**New file: `C:\Users\johnm\modular apartment planner\src\renderers\ColumnPreview.jsx`**

Follows the `DoorWindowPreview.jsx` pattern. Shows a translucent rectangle at the cursor position when the COLUMN tool is active.

```jsx
import { TOOLS } from '@/editor/tools';
import { COLUMN_WIDTH, COLUMN_DEPTH } from '@/domain/defaults';
import { columnOutline } from '@/geometry/columnGeometry';

export default function ColumnPreview({ toolState, activeTool }) {
  if (activeTool !== TOOLS.COLUMN) return null;
  if (toolState.previewX == null || toolState.previewY == null) return null;

  const previewColumn = {
    x: toolState.previewX,
    y: toolState.previewY,
    width: COLUMN_WIDTH,
    depth: COLUMN_DEPTH,
    rotation: 0,
  };

  const outline = columnOutline(previewColumn);
  const points = outline.map(p => `${p.x},${p.y}`).join(' ');

  return (
    <polygon
      points={points}
      fill="rgba(43, 127, 255, 0.2)"
      stroke="var(--color-selection)"
      strokeWidth={2}
      strokeDasharray="4 2"
      vectorEffect="non-scaling-stroke"
      style={{ pointerEvents: 'none' }}
    />
  );
}
```

